section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-bug-bash-runbook.json",
  "type": "object",
  "title": "QA Bug Bash Runbook",
  "required": [
    "bash_id",
    "release_id",
    "duration_minutes",
    "personas",
    "charters",
    "findings",
    "dedup_count",
    "ledger_path"
  ],
  "additionalProperties": false,
  "properties": {
    "bash_id": {
      "type": "string",
      "minLength": 1,
      "description": "Session id (date+release)."
    },
    "release_id": {
      "type": "string",
      "minLength": 1,
      "description": "Linked release identifier."
    },
    "duration_minutes": {
      "type": "integer",
      "description": "Total duration; \u226460."
    },
    "personas": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Personas covered."
    },
    "charters": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {persona, mission, tester, charter_id}."
    },
    "findings": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {id, title, severity, repro, screenshot}."
    },
    "dedup_count": {
      "type": "integer",
      "description": "Number of dedupped findings."
    },
    "ledger_path": {
      "type": "string",
      "minLength": 1,
      "description": "Path to committed bug ledger."
    }
  }
}

example.code:
{
  "bash_id": "bb-2026-05-23-v2.4",
  "release_id": "v2.4.0",
  "duration_minutes": 55,
  "personas": [
    "admin",
    "end_user",
    "integrator"
  ],
  "charters": [
    {
      "persona": "admin",
      "mission": "Bulk-edit member roles",
      "tester": "alice",
      "charter_id": "c1"
    }
  ],
  "findings": [
    {
      "id": "f1",
      "title": "Role bulk-edit ignores admin filter",
      "severity": "S2",
      "repro": "1. login admin 2. select 10 users 3. apply role",
      "screenshot": "https://i.example/abc"
    }
  ],
  "dedup_count": 3,
  "ledger_path": "release/v2.4/bug-bash-ledger.csv"
}
